import{_ as a,o as l,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"116. Meal Allowance","description":"","frontmatter":{"title":"116. Meal Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/116-meal-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/116-meal-allowance.md"}'),s={name:"ebas/mental-health/health-professionals/allowances/116-meal-allowance.md"};function n(r,e,c,h,i,p){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_116-meal-allowance" tabindex="-1">116. Meal Allowance <a class="header-anchor" href="#_116-meal-allowance" aria-label="Permalink to &quot;116. Meal Allowance&quot;">​</a></h1><p><strong>116.1</strong> An Employee shall be paid a meal allowance in accordance with <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>:</p><p><strong>116.2</strong> when overtime in excess of one hour is worked after the usual time of ceasing work for the day; or</p><p><strong>116.3</strong> when recalled to duty outside of usual working hours for a period in excess of two hours, and when the time of such recall coincides with or over-runs normal hospital meal time.</p><p><strong>116.4</strong> This clause shall not apply when a meal is supplied at the cost of the Employer.</p>',5)])])}const w=a(s,[["render",n]]);export{d as __pageData,w as default};
